import { writeFileSync } from 'fs'

function prod(id, name, slug, catId, catName, desc, shortDesc, specs, features, badge, sku) {
  const idStr = 'prod-' + String(id).padStart(3, '0')
  const badgeLine = badge ? `    badge: '${badge}',\n` : ''
  const specsLines = Object.entries(specs).map(([k,v]) => `      '${k}': '${v}',`).join('\n')
  const featuresLines = features.map(f => `      '${f}',`).join('\n')
  return `  {
    id: '${idStr}',
    name: '${name}',
    slug: '${slug}',
    categoryId: '${catId}',
    categoryName: '${catName}',
    description: '${desc}',
    shortDescription: '${shortDesc}',
    priceOnRequest: true,
    image: '',
    images: [],
    specifications: {
${specsLines}
    },
    features: [
${featuresLines}
    ],
    inStock: true,
${badgeLine}    sku: '${sku}',
  }`
}

